app = Flask(__name__)
app.secret_key = os.getenv("FLASK_SECRET_KEY", "change-me")

OIDC_ISSUER = os.getenv("OIDC_ISSUER", "https://example.com")
OIDC_CLIENT_ID = os.getenv("OIDC_CLIENT_ID", "your-client-id")
